export const meta = {
  name: 'qa-semantic-search',
  description: 'Execute semantic search for QA workflow',
  phases: [
    { title: 'SemanticSearch', detail: 'Search knowledge files for relevant sections' },
    { title: 'ReadSections', detail: 'Read selected sections content' }
  ]
}

phase('SemanticSearch')
const searchResult = await agent(
  `Execute the semantic search workflow at workflows/semantic-search.md in the directory /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6.

The search query is:
"2つの入力項目が一致しているかチェックしたい。メールアドレスと確認用メールアドレスの相関バリデーションのやり方を教えてほしい（処理方式: ウェブアプリケーション）（目的: 実装したい）"

Read the file /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/workflows/semantic-search.md first, then follow its instructions exactly.

The knowledge files are in /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/

Return a JSON object with:
- selected_pages: array of {path, reason} for pages selected
- excluded_pages: array of {path, reason} for pages explicitly considered but skipped
- selected_sections: array of {file, section_id, relevance, reason} where relevance is "high" or "partial"
- excluded_sections: array of {file, section_id, reason} for sections considered but skipped`,
  {
    label: 'semantic-search',
    phase: 'SemanticSearch',
    schema: {
      type: 'object',
      properties: {
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string', enum: ['high', 'partial'] },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
    }
  }
)

phase('ReadSections')
// Select sections: all high first, then partial, max 10
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

const readArgs = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`)
log(`Reading ${sectionsToRead.length} sections: ${readArgs.join(' ')}`)

const sectionsContent = await agent(
  `Run this bash command from directory /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6:

bash scripts/read-sections.sh ${readArgs.join(' ')}

Return the complete raw output of the command.`,
  { label: 'read-sections', phase: 'ReadSections' }
)

return {
  searchResult,
  sectionsToRead,
  sectionsContent
}

